(function () {
    var UTM_KEYS = { utm_source: 1, utm_medium: 1, utm_campaign: 1, utm_term: 1, utm_content: 1 };

    function oisclUtmsFromSearch(search) {
        var params = new URLSearchParams(search || '');
        var out = {};
        params.forEach(function (v, k) {
            var lk = String(k || '').toLowerCase();
            if (UTM_KEYS[lk]) {
                out[lk] = v;
            }
        });
        return out;
    }

    function oisclReadUtmCookie() {
        try {
            var m = document.cookie.match(/(?:^|;\s*)oiscl_utm_v1=([^;]*)/);
            if (!m) {
                return {};
            }
            return JSON.parse(decodeURIComponent(m[1])) || {};
        } catch (e) {
            return {};
        }
    }

    function oisclWriteUtmCookie(obj) {
        try {
            var s = encodeURIComponent(JSON.stringify(obj));
            if (s.length > 3800) {
                return;
            }
            var sec = location.protocol === 'https:' ? ';Secure' : '';
            // Session cookie (no Max-Age): lasts until the browser session ends — aligns with “while browsing” / incognito closes.
            document.cookie = 'oiscl_utm_v1=' + s + ';path=/;SameSite=Lax' + sec;
        } catch (e) {}
    }

    /**
     * First-touch + current URL: sessionStorage + session cookie survive internal navigation and extra tabs on the same site.
     * Current-page query params override stored keys when present (fresh campaign on the URL wins).
     * All beacons → admin-ajax `oiscl_track_click` → single table `oiscl_block_metrics` (Track Pro + every UTM admin tab read from here).
     */
    window.oisclMergeUtmPersistence = function () {
        var fromCookie = oisclReadUtmCookie();
        var fromSession = {};
        try {
            var raw = sessionStorage.getItem('oiscl_utm_v1');
            if (raw) {
                fromSession = JSON.parse(raw) || {};
            }
        } catch (e) {}
        var fromUrl = oisclUtmsFromSearch(window.location.search);
        var merged = Object.assign({}, fromCookie, fromSession, fromUrl);
        if (Object.keys(merged).length) {
            try {
                sessionStorage.setItem('oiscl_utm_v1', JSON.stringify(merged));
            } catch (e) {}
            oisclWriteUtmCookie(merged);
        }
        return merged;
    };

    try {
        window.oisclMergeUtmPersistence();
    } catch (e) {}
})();

document.addEventListener('DOMContentLoaded', function () {
    if (typeof oisclData === 'undefined') return;

    var blockEvent = oisclData.blockEvent || '[Vista de Bloque]';
    var pageviewEvent = oisclData.pageviewEvent || '[Pageview]';
    var instances = oisclData.tracking && oisclData.tracking.instances ? oisclData.tracking.instances : [];
    var instanceById = {};
    instances.forEach(function (inst) {
        instanceById[inst.id] = inst;
    });

    var isHuman = 0;
    var lastActivity = Date.now();
    var activeTime = 0;
    var blockEnterAt = {};
    var blockLogged = {};

    ['mousemove', 'scroll', 'touchstart', 'keydown', 'click'].forEach(function (e) {
        document.addEventListener(
            e,
            function () {
                isHuman = 1;
                lastActivity = Date.now();
            },
            { passive: true }
        );
    });
    setInterval(function () {
        if (Date.now() - lastActivity < 60000) {
            activeTime++;
        }
    }, 1000);

    var device = /Mobile|Android|iP(hone|od)/i.test(navigator.userAgent) ? 'Mobile' : /Tablet|iPad/i.test(navigator.userAgent) ? 'Tablet' : 'Desktop';
    var lang = (navigator.language || navigator.userLanguage).substring(0, 2);
    var vw = window.innerWidth || 0;
    var vh = window.innerHeight || 0;
    var screenRes = vw > 0 && vh > 0 ? String(vw) + 'x' + String(vh) : '';

    function cleanUrl(urlString) {
        try {
            var url = new URL(urlString);
            var params = new URLSearchParams(url.search);
            ['gclid', 'gad_source', 'utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', '_gl'].forEach(function (p) {
                params.delete(p);
            });
            url.search = params.toString();
            return url.toString().replace(/\/$/, '');
        } catch (e) {
            return urlString;
        }
    }

    function detectTrafficSource() {
        var params = new URLSearchParams(window.location.search);
        if (params.has('gclid') || params.has('gad_source')) return 'Google Ads';
        if (params.has('fbclid')) return 'Social Media';
        var ref = document.referrer.toLowerCase();
        if (!ref) return 'Direct Traffic';
        if (ref.indexOf('google.') !== -1) return 'Google Search';
        if (ref.indexOf('facebook.com') !== -1 || ref.indexOf('instagram.com') !== -1) return 'Social Media';
        return 'Referral';
    }

    try {
        if (typeof window.oisclMergeUtmPersistence === 'function') {
            window.oisclMergeUtmPersistence();
        }
    } catch (e) {}

    function normText(t) {
        return String(t || '')
            .replace(/\s+/g, ' ')
            .trim()
            .substring(0, 120);
    }

    function sendData(anchor, dest, context, instanceId, dwellSec) {
        var formData = new FormData();
        formData.append('action', 'oiscl_track_click');
        formData.append('nonce', oisclData.nonce);
        formData.append('post_id', oisclData.postId);
        formData.append('origin_url', window.location.href);
        formData.append('traffic_source', detectTrafficSource());
        formData.append('anchor_text', anchor);
        formData.append('destination_url', dest);
        formData.append('context_text', context);
        formData.append('time_spent', dwellSec != null ? dwellSec : activeTime);
        formData.append('device', device);
        formData.append('language', lang);
        formData.append('screen_res', screenRes);
        formData.append('is_bot', isHuman ? 0 : 1);
        if (instanceId) formData.append('instance_id', instanceId);
        var utmCtx = typeof window.oisclMergeUtmPersistence === 'function' ? window.oisclMergeUtmPersistence() : {};
        ['utm_campaign', 'utm_term', 'utm_source', 'utm_medium'].forEach(function (k) {
            if (utmCtx[k]) formData.append(k, utmCtx[k]);
        });
        if (navigator.sendBeacon) {
            navigator.sendBeacon(oisclData.ajaxUrl, formData);
        } else {
            fetch(oisclData.ajaxUrl, { method: 'POST', body: formData, keepalive: true });
        }
    }

    function elementLabel(el) {
        if (!el) return '';
        if (el.tagName === 'INPUT') return normText(el.value || el.getAttribute('aria-label') || '');
        return normText(el.innerText || el.textContent || '');
    }

    function matchInstanceForElement(el) {
        var tag = el.tagName ? el.tagName.toUpperCase() : '';
        var text = elementLabel(el);
        if (!text) return null;
        var index = 0;
        var nodes = document.querySelectorAll(el.tagName);
        for (var i = 0; i < nodes.length; i++) {
            if (nodes[i] === el) break;
            if (elementLabel(nodes[i]) === text) index++;
        }
        var wantId = null;
        instances.forEach(function (inst) {
            if (inst.tag === tag && normText(inst.text) === text && (inst.index === undefined || inst.index === index)) {
                wantId = inst.id;
            }
        });
        if (!wantId) {
            instances.forEach(function (inst) {
                if (inst.tag === tag && normText(inst.text) === text) wantId = inst.id;
            });
        }
        return wantId ? instanceById[wantId] : null;
    }

    function stampInstances() {
        instances.forEach(function (inst) {
            var selector =
                inst.tag === 'A'
                    ? 'a'
                    : inst.tag === 'BUTTON'
                      ? 'button'
                      : inst.tag === 'INPUT'
                        ? 'input[type="submit"], input[type="button"]'
                        : inst.tag.toLowerCase();
            var nodes = document.querySelectorAll(selector);
            nodes.forEach(function (el) {
                if (elementLabel(el) !== normText(inst.text)) return;
                el.setAttribute('data-ois-iid', inst.id);
            });
        });
    }
    stampInstances();
    setTimeout(stampInstances, 800);
    setTimeout(stampInstances, 2500);
    if (window.MutationObserver && document.querySelector('.nf-form-cont, .ninja-forms-form-wrap')) {
        var oisMo = new MutationObserver(function () {
            stampInstances();
        });
        oisMo.observe(document.body, { childList: true, subtree: true });
        setTimeout(function () {
            oisMo.disconnect();
        }, 12000);
    }

    if (parseInt(oisclData.postId, 10) === 0) {
        sendData('[Error 404]', window.location.href, 'Página no encontrada', '', 0);
    } else {
        sendData(pageviewEvent, detectTrafficSource(), 'Visit', '', 0);
    }

    document.addEventListener('click', function (e) {
        var target = e.target.closest('a, button, input[type="submit"], input[type="button"], [role="button"]');
        if (!target) return;
        isHuman = 1;
        var inst = matchInstanceForElement(target);
        if (inst && !inst.track_click) return;
        if (!inst && instances.length > 0) {
            var anyClickTracked = instances.some(function (i) {
                return i.track_click;
            });
            if (anyClickTracked) return;
        }
        var dest = target.href || (target.tagName === 'BUTTON' || target.tagName === 'INPUT' ? '[Form Submit]' : '[Interactive]');
        if (dest.indexOf('maps.google.com') !== -1) return;
        var anchor = elementLabel(target).substring(0, 50) || '[Icon/Image]';
        var alias = inst && inst.alias ? inst.alias : anchor;
        sendData(anchor, cleanUrl(dest), alias, inst ? inst.id : '', 0);
    });

    var viewTargets = [];
    instances.forEach(function (inst) {
        if (!inst.track_view) return;
        var sel = inst.tag === 'SECTION' ? 'section' : inst.tag.toLowerCase();
        if (inst.tag === 'A' || inst.tag === 'BUTTON') return;
        document.querySelectorAll(sel).forEach(function (el) {
            if (normText(el.innerText || el.textContent) !== normText(inst.text)) return;
            el.setAttribute('data-ois-iid', inst.id);
            viewTargets.push({ el: el, inst: inst });
        });
    });

    if (viewTargets.length === 0 && instances.length === 0 && oisclData.trackTags) {
        document.querySelectorAll(oisclData.trackTags).forEach(function (el) {
            viewTargets.push({
                el: el,
                inst: { id: '', alias: normText(el.innerText).substring(0, 40), track_view: true },
            });
        });
    }

    var observer = new IntersectionObserver(
        function (entries) {
            entries.forEach(function (entry) {
                var el = entry.target;
                var iid = el.getAttribute('data-ois-iid') || '';
                var inst = iid && instanceById[iid] ? instanceById[iid] : null;
                if (entry.isIntersecting) {
                    if (!blockEnterAt[iid || el.tagName]) {
                        blockEnterAt[iid || el.tagName] = Date.now();
                    }
                    setTimeout(function () {
                        if (!entry.isIntersecting) return;
                        var rect = el.getBoundingClientRect();
                        if (rect.top >= window.innerHeight || rect.bottom < 0) return;
                        var key = iid || el.tagName;
                        if (blockLogged[key]) return;
                        blockLogged[key] = true;
                        var alias = inst && inst.alias ? inst.alias : normText(el.innerText).substring(0, 40);
                        sendData(blockEvent, 'block_view', alias, inst ? inst.id : '', 0);
                        if (oisclData.auditMode) {
                            el.classList.add('oiscl-audit-highlight');
                            el.setAttribute('data-ois-stats', '👁️ tracked');
                        }
                    }, 2000);
                } else if (blockEnterAt[iid || el.tagName]) {
                    var dwell = Math.round((Date.now() - blockEnterAt[iid || el.tagName]) / 1000);
                    if (dwell > 2 && inst) {
                        var alias = inst.alias || inst.text;
                        sendData(blockEvent, 'dwell', alias, inst.id, dwell);
                    }
                    delete blockEnterAt[iid || el.tagName];
                }
            });
        },
        { threshold: 0.3 }
    );

    viewTargets.forEach(function (v) {
        observer.observe(v.el);
    });

    if (oisclData.auditMode) {
        setTimeout(function () {
            document.querySelectorAll('[data-ois-iid]').forEach(function (el) {
                el.style.outline = '1px dashed #3b82f6';
            });
        }, 1200);
    }
});
